import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  FaHardHat, 
  FaUsers, 
  FaFileContract, 
  FaIndustry,
  FaCheckCircle,
  FaAward,
  FaChartLine,
  FaRocket,
  FaStar,
  FaShieldAlt,
  FaBolt,
  FaMoon,
  FaSun
} from 'react-icons/fa';
import './Home-Modern.css';

const Home = () => {
  const [darkMode, setDarkMode] = useState(false);

  const toggleDarkMode = () => {
    setDarkMode(!darkMode);
    document.body.classList.toggle('dark-mode');
  };

  return (
    <main>
      {/* Dark Mode Toggle */}
      <motion.button
        onClick={toggleDarkMode}
        className="dark-mode-toggle"
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.95 }}
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.5 }}
      >
        {darkMode ? <FaSun /> : <FaMoon />}
      </motion.button>

      {/* Enhanced Hero Section */}
      <section className="hero-modern">
        <div className="container">
          <motion.div 
            className="hero-content-modern"
            initial={{ opacity: 0, y: 50 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
          >
            {/* Badge */}
            <motion.div
              className="hero-badge"
              initial={{ opacity: 0, scale: 0.5 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ delay: 0.2, duration: 0.6 }}
            >
              <FaRocket />
              <span>India's Leading Construction Partner</span>
              <FaStar />
            </motion.div>

            {/* Main Heading */}
            <h1 className="hero-title">
              <motion.span
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.3 }}
              >
                Building Tomorrow's
              </motion.span>
              <motion.span 
                className="hero-title-gradient"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.5 }}
              >
                Infrastructure Today
              </motion.span>
            </h1>

            {/* Description */}
            <motion.p 
              className="hero-description"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.7 }}
            >
              Pioneering Government Tenders & AAC Blocks Manpower Solutions 
              with cutting-edge technology and unmatched expertise
            </motion.p>

            {/* CTA Buttons */}
            <motion.div 
              className="hero-buttons"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.9 }}
            >
              <Link to="/services" className="hero-btn-primary">
                <span>Explore Services</span>
                <FaBolt />
              </Link>
              <Link to="/contact" className="hero-btn-secondary">
                Get Started →
              </Link>
            </motion.div>

            {/* Trust Badges */}
            <motion.div 
              className="hero-trust-badges"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 1.1 }}
            >
              <div className="trust-badge-item">
                <FaShieldAlt className="trust-badge-icon" style={{ color: '#10b981' }} />
                <span>ISO Certified</span>
              </div>
              <div className="trust-badge-item">
                <FaAward className="trust-badge-icon" style={{ color: '#f59e0b' }} />
                <span>15+ Years</span>
              </div>
              <div className="trust-badge-item">
                <FaStar className="trust-badge-icon" style={{ color: '#fbbf24' }} />
                <span>500+ Projects</span>
              </div>
            </motion.div>
          </motion.div>
        </div>

        {/* Scroll Indicator */}
        <div className="scroll-indicator"></div>
      </section>

      {/* Modern Stats Section */}
      <section className="stats-modern">
        <div className="container">
          <div className="stats-grid-modern">
            {[
              { icon: FaFileContract, number: '500+', label: 'Tenders Completed' },
              { icon: FaUsers, number: '2000+', label: 'Skilled Workers' },
              { icon: FaIndustry, number: '50+', label: 'AAC Plants' },
              { icon: FaAward, number: '15+', label: 'Years Excellence' },
            ].map((stat, index) => (
              <motion.div
                key={index}
                className="stat-card-modern"
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5, delay: index * 0.1 }}
                viewport={{ once: true }}
                whileHover={{ scale: 1.05 }}
              >
                <div className="stat-icon-wrapper">
                  <stat.icon className="stat-icon" />
                </div>
                <h3 className="stat-number">{stat.number}</h3>
                <p className="stat-label">{stat.label}</p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Futuristic Services Section */}
      <section className="services-modern">
        <div className="container">
          <motion.div 
            className="section-header-modern"
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
          >
            <h2 className="section-title-modern">
              Our <span className="gradient-text">Core Services</span>
            </h2>
            <p className="section-subtitle">
              Comprehensive construction and manpower solutions powered by innovation
            </p>
          </motion.div>

          <div className="services-grid-modern">
            {[
              {
                icon: FaFileContract,
                title: 'Government Tenders',
                description: 'Specialized in bidding and executing government construction projects with complete documentation.',
                features: ['Tender Documentation', 'Project Execution', 'Compliance Management'],
                featured: false
              },
              {
                icon: FaIndustry,
                title: 'AAC Blocks Manpower',
                description: 'Expert workforce solutions for AAC blocks manufacturing plants with trained personnel.',
                features: ['Skilled Operators', 'Plant Maintenance', 'Quality Control'],
                featured: true
              },
              {
                icon: FaHardHat,
                title: 'Construction Management',
                description: 'End-to-end construction project management from planning to execution.',
                features: ['Project Planning', 'Resource Management', 'Quality Assurance'],
                featured: false
              }
            ].map((service, index) => (
              <motion.div
                key={index}
                className={`service-card-modern ${service.featured ? 'service-card-featured' : ''}`}
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5, delay: index * 0.1 }}
                viewport={{ once: true }}
              >
                {service.featured && (
                  <div className="featured-badge">Most Popular</div>
                )}

                <div className="service-icon-modern">
                  <service.icon />
                </div>

                <h3 className="service-title">{service.title}</h3>
                <p className="service-description">{service.description}</p>

                <ul className="service-features-list">
                  {service.features.map((feature, idx) => (
                    <li key={idx} className="service-feature-item">
                      <FaCheckCircle className="service-feature-icon" />
                      {feature}
                    </li>
                  ))}
                </ul>

                <Link to="/services" className="service-link">
                  <span>Learn More</span>
                  <span className="service-link-arrow">→</span>
                </Link>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Modern Why Choose Us Section */}
      <section className="why-choose-modern">
        <div className="container">
          <div className="why-choose-grid">
            <motion.div
              className="why-choose-content"
              initial={{ opacity: 0, x: -50 }}
              whileInView={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8 }}
              viewport={{ once: true }}
            >
              <h2 className="why-choose-title">
                Why Choose <span className="gradient-text">BuildPro</span>?
              </h2>
              <p className="why-choose-description">
                With over 15 years of industry experience, we deliver unmatched 
                expertise in construction and manpower services.
              </p>

              <div className="features-modern-grid">
                {[
                  { title: 'Proven Track Record', desc: '500+ government projects completed successfully', icon: FaAward },
                  { title: 'Expert Workforce', desc: '2000+ trained and certified professionals', icon: FaUsers },
                  { title: 'Quality Assurance', desc: 'ISO certified processes and standards', icon: FaShieldAlt },
                  { title: 'Timely Delivery', desc: '98% on-time project completion rate', icon: FaRocket }
                ].map((item, index) => (
                  <motion.div
                    key={index}
                    className="feature-card-modern"
                    initial={{ opacity: 0, x: -20 }}
                    whileInView={{ opacity: 1, x: 0 }}
                    transition={{ delay: index * 0.1 }}
                    viewport={{ once: true }}
                  >
                    <div className="feature-icon-modern">
                      <item.icon />
                    </div>
                    <div className="feature-content">
                      <h4>{item.title}</h4>
                      <p>{item.desc}</p>
                    </div>
                  </motion.div>
                ))}
              </div>

              <Link to="/about" className="btn btn-primary">
                Learn More About Us →
              </Link>
            </motion.div>

            <motion.div
              className="why-choose-visual"
              initial={{ opacity: 0, x: 50 }}
              whileInView={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8 }}
              viewport={{ once: true }}
            >
              <div className="visual-placeholder">
                <FaChartLine className="visual-icon" />
                <p>Excellence in Every Project</p>
              </div>

              {/* Floating Stats */}
              <div className="floating-stat floating-stat-1">
                <div className="floating-stat-number">98%</div>
                <div className="floating-stat-label">Success Rate</div>
              </div>

              <div className="floating-stat floating-stat-2">
                <div className="floating-stat-number">24/7</div>
                <div className="floating-stat-label">Support</div>
              </div>
            </motion.div>
          </div>
        </div>
      </section>

      {/* Futuristic CTA Section */}
      <section className="cta-modern">
        <div className="container">
          <motion.div 
            className="cta-content-modern"
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
            viewport={{ once: true }}
          >
            <div className="cta-icon-wrapper">
              <FaRocket className="cta-icon" />
            </div>

            <h2 className="cta-title">
              Ready to Start Your Next Project?
            </h2>
            <p className="cta-description">
              Get in touch with our experts for a free consultation and quote
            </p>

            <div className="cta-buttons">
              <Link to="/contact" className="cta-btn-primary">
                <span>Contact Us Today</span>
                <FaBolt />
              </Link>
              <Link to="/projects" className="cta-btn-secondary">
                View Our Projects
              </Link>
            </div>

            {/* Trust Indicators */}
            <div className="cta-stats">
              <div className="cta-stat-item">
                <div className="cta-stat-number">500+</div>
                <div className="cta-stat-label">Projects Delivered</div>
              </div>
              <div className="cta-stat-item">
                <div className="cta-stat-number">98%</div>
                <div className="cta-stat-label">Client Satisfaction</div>
              </div>
              <div className="cta-stat-item">
                <div className="cta-stat-number">24/7</div>
                <div className="cta-stat-label">Support Available</div>
              </div>
            </div>
          </motion.div>
        </div>
      </section>
    </main>
  );
};

export default Home;
